1202 bool IndVarSimplify::sinkUnusedInvariants(Loop *L) {
1203   BasicBlock *ExitBlock = L->getExitBlock();
1204   if (!ExitBlock)
1205     return false;
1206 
1207   BasicBlock *Preheader = L->getLoopPreheader();
1208   if (!Preheader)
1209     return false;
1210 
1211   bool MadeAnyChanges = false;
1212   for (Instruction &I : llvm::make_early_inc_range(llvm::reverse(*Preheader))) {
1213 
1214     // Skip BB Terminator.
1215     if (Preheader->getTerminator() == &I)
1216       continue;
1217 
1218     // New instructions were inserted at the end of the preheader.
1219     if (isa<PHINode>(I))
1220       break;
1221 
1222     // Don't move instructions which might have side effects, since the side
1223     // effects need to complete before instructions inside the loop.  Also don't
1224     // move instructions which might read memory, since the loop may modify
1225     // memory. Note that it's okay if the instruction might have undefined
1226     // behavior: LoopSimplify guarantees that the preheader dominates the exit
1227     // block.
1228     if (I.mayHaveSideEffects() || I.mayReadFromMemory())
1229       continue;
1230 
1231     // Skip debug or pseudo instructions.
1232     if (I.isDebugOrPseudoInst())
1233       continue;
1234 
1235     // Skip eh pad instructions.
1236     if (I.isEHPad())
1237       continue;
1238 
1239     // Don't sink alloca: we never want to sink static alloca's out of the
1240     // entry block, and correctly sinking dynamic alloca's requires
1241     // checks for stacksave/stackrestore intrinsics.
1242     // FIXME: Refactor this check somehow?
1243     if (isa<AllocaInst>(&I))
1244       continue;
1245 
1246     // Determine if there is a use in or before the loop (direct or
1247     // otherwise).
1248     bool UsedInLoop = false;
1249     for (Use &U : I.uses()) {
1250       Instruction *User = cast<Instruction>(U.getUser());
1251       BasicBlock *UseBB = User->getParent();
1252       if (PHINode *P = dyn_cast<PHINode>(User)) {
1253         unsigned i = PHINode::getIncomingValueNumForOperand(U.getOperandNo());
1254         UseBB = P->getIncomingBlock(i);
1255       }
1256       if (UseBB == Preheader || L->contains(UseBB)) {
1257         UsedInLoop = true;
1258         break;
1259       }
1260     }
1261 
1262     // If there is, the def must remain in the preheader.
1263     if (UsedInLoop)
1264       continue;
1265 
1266     // Otherwise, sink it to the exit block.
1267     I.moveBefore(ExitBlock->getFirstInsertionPt());
1268     SE->forgetValue(&I);
1269     MadeAnyChanges = true;
1270   }
1271 
1272   return MadeAnyChanges;
1273 }
