1011 /// Insert an IR expression which computes the value held by the IV IndVar
1012 /// (which must be an loop counter w/unit stride) after the backedge of loop L
1013 /// is taken ExitCount times.
1014 static Value *genLoopLimit(PHINode *IndVar, BasicBlock *ExitingBB,
1015                            const SCEV *ExitCount, bool UsePostInc, Loop *L,
1016                            SCEVExpander &Rewriter, ScalarEvolution *SE) {
1017   assert(isLoopCounter(IndVar, L, SE));
1018   assert(ExitCount->getType()->isIntegerTy() && "exit count must be integer");
1019   const SCEVAddRecExpr *AR = cast<SCEVAddRecExpr>(SE->getSCEV(IndVar));
1020   assert(AR->getStepRecurrence(*SE)->isOne() && "only handles unit stride");
1021 
1022   // For integer IVs, truncate the IV before computing the limit unless we
1023   // know apriori that the limit must be a constant when evaluated in the
1024   // bitwidth of the IV.  We prefer (potentially) keeping a truncate of the
1025   // IV in the loop over a (potentially) expensive expansion of the widened
1026   // exit count add(zext(add)) expression.
1027   if (IndVar->getType()->isIntegerTy() &&
1028       SE->getTypeSizeInBits(AR->getType()) >
1029           SE->getTypeSizeInBits(ExitCount->getType())) {
1030     const SCEV *IVInit = AR->getStart();
1031     if (!isa<SCEVConstant>(IVInit) || !isa<SCEVConstant>(ExitCount)) {
1032       const SCEV *TruncExpr = SE->getTruncateExpr(AR, ExitCount->getType());
1033 
1034       // The following bailout is necessary due to the interaction with
1035       // the depth limit in SCEV analysis.
1036       if (!isa<SCEVAddRecExpr>(TruncExpr))
1037         return nullptr;
1038       AR = cast<SCEVAddRecExpr>(TruncExpr);
1039     }
1040   }
1041 
1042   const SCEVAddRecExpr *ARBase = UsePostInc ? AR->getPostIncExpr(*SE) : AR;
1043   const SCEV *IVLimit = ARBase->evaluateAtIteration(ExitCount, *SE);
1044   assert(SE->isLoopInvariant(IVLimit, L) &&
1045          "Computed iteration count is not loop invariant!");
1046   return Rewriter.expandCodeFor(IVLimit, ARBase->getType(),
1047                                 ExitingBB->getTerminator());
1048 }
