1065   Value *CmpIndVar = IndVar;
1066   bool UsePostInc = false;
1067 
1068   // If the exiting block is the same as the backedge block, we prefer to
1069   // compare against the post-incremented value, otherwise we must compare
1070   // against the preincremented value.
1071   if (ExitingBB == L->getLoopLatch()) {
1072     // For pointer IVs, we chose to not strip inbounds which requires us not
1073     // to add a potentially UB introducing use.  We need to either a) show
1074     // the loop test we're modifying is already in post-inc form, or b) show
1075     // that adding a use must not introduce UB.
1076     bool SafeToPostInc =
1077         IndVar->getType()->isIntegerTy() ||
1078         isLoopExitTestBasedOn(IncVar, ExitingBB) ||
1079         mustExecuteUBIfPoisonOnPathTo(IncVar, ExitingBB->getTerminator(), DT);
1080     if (SafeToPostInc) {
1081       UsePostInc = true;
1082       CmpIndVar = IncVar;
1083     }
1084   }
1085 
1086   Value *ExitCnt =
1087       genLoopLimit(IndVar, ExitingBB, ExitCount, UsePostInc, L, Rewriter, SE);
1088   if (!ExitCnt)
1089     return false;
1090 
1091   assert(ExitCnt->getType()->isPointerTy() ==
1092              IndVar->getType()->isPointerTy() &&
1093          "genLoopLimit missed a cast");
1094 
1095   // It may be necessary to drop nowrap flags on the incrementing instruction
1096   // if either LFTR moves from a pre-inc check to a post-inc check (in which
1097   // case the increment might have previously been poison on the last iteration
1098   // only) or if LFTR switches to a different IV that was previously dynamically
1099   // dead (and as such may be arbitrarily poison). We remove any nowrap flags
1100   // that SCEV didn't infer for the post-inc addrec (even if we use a pre-inc
1101   // check), because the pre-inc addrec flags may be adopted from the original
1102   // instruction, while SCEV has to explicitly prove the post-inc nowrap flags.
1103   // TODO: This handling is inaccurate for one case: If we switch to a
1104   // dynamically dead IV that wraps on the first loop iteration only, which is
1105   // not covered by the post-inc addrec. (If the new IV was not dynamically
1106   // dead, it could not be poison on the first iteration in the first place.)
1107   if (auto *BO = dyn_cast<BinaryOperator>(IncVar)) {
1108     const SCEVAddRecExpr *AR = cast<SCEVAddRecExpr>(SE->getSCEV(IncVar));
1109     if (BO->hasNoUnsignedWrap())
1110       BO->setHasNoUnsignedWrap(AR->hasNoUnsignedWrap());
1111     if (BO->hasNoSignedWrap())
1112       BO->setHasNoSignedWrap(AR->hasNoSignedWrap());
1113   }
1114 
1115   // Insert a new icmp_ne or icmp_eq instruction before the branch.
1116   BranchInst *BI = cast<BranchInst>(ExitingBB->getTerminator());
1117   ICmpInst::Predicate P;
1118   if (L->contains(BI->getSuccessor(0)))
1119     P = ICmpInst::ICMP_NE;
1120   else
1121     P = ICmpInst::ICMP_EQ;
1122 
1123   IRBuilder<> Builder(BI);
1124 
1125   // The new loop exit condition should reuse the debug location of the
1126   // original loop exit condition.
1127   if (auto *Cond = dyn_cast<Instruction>(BI->getCondition()))
1128     Builder.SetCurrentDebugLocation(Cond->getDebugLoc());
1129 
1130   // For integer IVs, if we evaluated the limit in the narrower bitwidth to
1131   // avoid the expensive expansion of the limit expression in the wider type,
1132   // emit a truncate to narrow the IV to the ExitCount type.  This is safe
1133   // since we know (from the exit count bitwidth), that we can't self-wrap in
1134   // the narrower type.
1135   unsigned CmpIndVarSize = SE->getTypeSizeInBits(CmpIndVar->getType());
1136   unsigned ExitCntSize = SE->getTypeSizeInBits(ExitCnt->getType());
1137   if (CmpIndVarSize > ExitCntSize) {
1138     assert(!CmpIndVar->getType()->isPointerTy() &&
1139            !ExitCnt->getType()->isPointerTy());
1140 
1141     // Before resorting to actually inserting the truncate, use the same
1142     // reasoning as from SimplifyIndvar::eliminateTrunc to see if we can extend
1143     // the other side of the comparison instead.  We still evaluate the limit
1144     // in the narrower bitwidth, we just prefer a zext/sext outside the loop to
1145     // a truncate within in.
1146     bool Extended = false;
1147     const SCEV *IV = SE->getSCEV(CmpIndVar);
1148     const SCEV *TruncatedIV = SE->getTruncateExpr(IV, ExitCnt->getType());
1149     const SCEV *ZExtTrunc =
1150         SE->getZeroExtendExpr(TruncatedIV, CmpIndVar->getType());
