1152     if (ZExtTrunc == IV) {
1153       Extended = true;
1154       ExitCnt =
1155           Builder.CreateZExt(ExitCnt, IndVar->getType(), "wide.trip.count");
1156     } else {
1157       const SCEV *SExtTrunc =
1158           SE->getSignExtendExpr(TruncatedIV, CmpIndVar->getType());
1159       if (SExtTrunc == IV) {
1160         Extended = true;
1161         ExitCnt =
1162             Builder.CreateSExt(ExitCnt, IndVar->getType(), "wide.trip.count");
1163       }
1164     }
1165 
1166     if (Extended) {
1167       bool Discard;
1168       L->makeLoopInvariant(ExitCnt, Discard);
1169     } else
1170       CmpIndVar =
1171           Builder.CreateTrunc(CmpIndVar, ExitCnt->getType(), "lftr.wideiv");
1172   }
1173   LLVM_DEBUG(dbgs() << "INDVARS: Rewriting loop exit condition to:\n"
1174                     << "      LHS:" << *CmpIndVar << '\n'
1175                     << "       op:\t" << (P == ICmpInst::ICMP_NE ? "!=" : "==")
1176                     << "\n"
1177                     << "      RHS:\t" << *ExitCnt << "\n"
1178                     << "ExitCount:\t" << *ExitCount << "\n"
1179                     << "  was: " << *BI->getCondition() << "\n");
1180 
1181   Value *Cond = Builder.CreateICmp(P, CmpIndVar, ExitCnt, "exitcond");
1182   Value *OrigCond = BI->getCondition();
1183   // It's tempting to use replaceAllUsesWith here to fully replace the old
1184   // comparison, but that's not immediately safe, since users of the old
1185   // comparison may not be dominated by the new comparison. Instead, just
1186   // update the branch to use the new comparison; in the common case this
1187   // will make old comparison dead.
1188   BI->setCondition(Cond);
1189   DeadInsts.emplace_back(OrigCond);
1190 
1191   ++NumLFTR;
1192   return true;
1193 }
